mapper.select:
SELECT id, behavior_code, score_type, score_val, create_time, update_time
FROM user_behavior_score
WHERE id = #{id}

SELECT id, behavior_code, score_type, score_val, create_time, update_time
FROM user_behavior_score
WHERE behavior_code = #{behaviorCode}
  AND score_type = #{scoreType}

SELECT id, behavior_code, score_type, score_val, create_time, update_time
FROM user_behavior_score
WHERE behavior_code = #{behaviorCode}

mapper.update:
UPDATE user_behavior_score
behavior_code = #{behaviorCode}, score_type = #{scoreType}, score_val = #{scoreVal}, update_time = NOW()
WHERE id = #{id}

UPDATE user_behavior_score
SET score_val = #{scoreVal},
    update_time = NOW()
WHERE behavior_code = #{behaviorCode}
  AND score_type = #{scoreType}

mapper.delete:
DELETE FROM user_behavior_score
WHERE behavior_code = #{behaviorCode}
  AND score_type = #{scoreType}
